import React, { useState, useEffect } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import axios from 'axios'
import styled from 'styled-components'


const StyledForm = styled.form`
    display: flex;
    flex-direction: column;
`

const PostEdit = ({ setPosts }) => {
    let { id } = useParams()
    let navigate = useNavigate()

    const initialState = {
        status_body: '',
        date: '',
        file: ''
    }

    const [formData, setFormData] = useState(initialState)

    const handleChange = (e) => {
        console.log(e.target)
        setFormData({...formData, [e.target.id] : e.target.value})
    }


    const handleSubmit = (e) => {
        e.preventDefault()
        console.log(formData)
        axios.put(`http://localhost:8000/bunnybook/posts/${id}/`, formData )
        .then(res =>  {

            setFormData(initialState)
            setPosts(res.data)
            navigate('/', { replace: true })
        })

    }

    useEffect(()=> {
        axios.get(`http://localhost:8000/bunnybook/posts/${id}`)
        .then(res => {
            setFormData(res.data)
            console.log(res.data)
        })
    }, [id])

  return (
        <StyledForm onSubmit={handleSubmit}>
                       <div>
                <label htmlFor='status_body'>Post</label>
                <input id='status_body' name='status_body' value={formData?.status_body} type='text' onChange={handleChange} />
            </div>
            <div>
                <label htmlFor='date'>Date</label>
                <input id='date' name='date' type='text' value={formData?.date}  onChange={handleChange} />
            </div>
            <div>
                <label htmlFor='file'>File</label>
                <input id='file' name='file' type='image' value={formData?.file}  onChange={handleChange} />
            </div>


            <input type='submit' value='Edit Post' />

        </StyledForm>
  )
}

export default PostEdit
